function run(inputs, ctx) {
  const n = Math.max(1, Math.round(inputs.n ?? 5));
  const L = inputs.L ?? Math.PI;
  const N = 500;
  const expr = ctx.expressions.find(e => e.id === ctx.exprId);
  if (!expr) return { ok: false, error: 'No expression', data: {} };
  // Numerically integrate using ctx.userFns
  function evalAt(x) {
    try {
      const fns = ctx.userFns;
      const env = { ...ctx.env, x };
      // Evaluate by calling the expression's function if defined
      const name = expr.parsed && expr.parsed.type === 'function' ? expr.parsed.name : null;
      if (name && fns[name]) return fns[name]([x]);
      return NaN;
    } catch { return NaN; }
  }
  function integrate(fn, a, b, steps) {
    const h = (b - a) / steps;
    let s = 0;
    for (let i = 0; i <= steps; i++) {
      const x = a + i * h;
      const w = (i === 0 || i === steps) ? 0.5 : 1;
      const v = fn(x);
      if (isFinite(v)) s += w * v * h;
    }
    return s;
  }
  const a0 = (1 / L) * integrate(x => evalAt(x), -L, L, N);
  const coeffs = [];
  let latex = `\\frac{${a0.toFixed(3)}}{2}`;
  for (let k = 1; k <= n; k++) {
    const ak = (1 / L) * integrate(x => evalAt(x) * Math.cos(k * Math.PI * x / L), -L, L, N);
    const bk = (1 / L) * integrate(x => evalAt(x) * Math.sin(k * Math.PI * x / L), -L, L, N);
    coeffs.push({ k, ak: parseFloat(ak.toFixed(4)), bk: parseFloat(bk.toFixed(4)) });
    if (Math.abs(ak) > 1e-6) latex += ` + ${ak.toFixed(3)}\\cos\\!\\left(\\tfrac{${k}\\pi x}{L}\\right)`;
    if (Math.abs(bk) > 1e-6) latex += ` + ${bk.toFixed(3)}\\sin\\!\\left(\\tfrac{${k}\\pi x}{L}\\right)`;
  }
  return {
    ok: true,
    data: {
      a0: parseFloat(a0.toFixed(4)),
      coefficients: coeffs,
      latex,
      n_terms: n,
      period: 2 * L
    }
  };
}
